import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Use nextLine() to read the whole line

        int maxLength = 10; // Maximum length of the buffer
        char[] buffer = new char[maxLength];

        // Copy the user input into the buffer with bounds checking
        for (int i = 0; i < input.length() && i < maxLength; i++) {
            buffer[i] = input.charAt(i);
        }

        // Ensure null-termination of the char array
        if (input.length() >= maxLength) {
            buffer[maxLength - 1] = '\0';
        } else {
            buffer[input.length()] = '\0';
        }

        System.out.println("Input stored securely in buffer.");
    }
}

